SELECT * FROM duckdb_extensions();



INSTALL httpfs;
LOAD httpfs;

CREATE TABLE cities AS SELECT * FROM 'https://data.gishub.org/duckdb/cities.csv';



CREATE TABLE countries AS SELECT * FROM 'https://data.gishub.org/duckdb/countries.csv';



FROM cities;



FROM countries;

SELECT name, country, population FROM cities
ORDER BY population DESC LIMIT 10;



SELECT name, latitude, longitude FROM cities
ORDER BY latitude DESC, longitude ASC LIMIT 10;

SELECT * FROM cities WHERE country='USA';



SELECT * FROM cities WHERE country='USA' OR country='CAN';



SELECT * FROM cities WHERE country='USA' AND population>1000000;

SELECT * FROM cities WHERE country LIKE 'U%';



SELECT * FROM cities WHERE country LIKE '%A';



SELECT * FROM cities WHERE country LIKE '_S_';

SELECT COUNT(*) FROM cities;



SELECT * FROM cities LIMIT 10;



SELECT COUNT(*) FROM countries;



SELECT * FROM countries LIMIT 10;

SELECT country FROM cities
UNION
SELECT "Alpha3_code" FROM countries;

CREATE TABLE cities2 AS SELECT * FROM cities;



FROM cities2;



DROP TABLE IF EXISTS cities_usa;
CREATE TABLE cities_usa AS (SELECT * FROM cities WHERE country = 'USA');



FROM cities_usa;



INSERT INTO cities_usa (SELECT * FROM cities WHERE country = 'CAN');

SELECT name, population FROM cities
WHERE population > 1000000 -- Filter for major cities only
ORDER BY population DESC LIMIT 10;

con.sql(
    "COPY (SELECT * EXCLUDE geometry FROM cities) TO 'cities.xlsx' WITH (FORMAT xlsx, HEADER true)"
)

con.sql(
    "COPY (SELECT * FROM cities WHERE population > 1000000) TO 'major_cities.gpkg' WITH (FORMAT GDAL, DRIVER 'GPKG')"
)

con.sql(
    """
CREATE OR REPLACE TABLE samples (name VARCHAR, geom GEOMETRY);

INSERT INTO samples VALUES
  ('Point', ST_GeomFromText('POINT(-100 40)')),
  ('Linestring', ST_GeomFromText('LINESTRING(0 0, 1 1, 2 1, 2 2)')),
  ('Polygon', ST_GeomFromText('POLYGON((0 0, 1 0, 1 1, 0 1, 0 0))')),
  ('PolygonWithHole', ST_GeomFromText('POLYGON((0 0, 10 0, 10 10, 0 10, 0 0),(1 1, 1 2, 2 2, 2 1, 1 1))')),
  ('Collection', ST_GeomFromText('GEOMETRYCOLLECTION(POINT(2 0),POLYGON((0 0, 1 0, 1 1, 0 1, 0 0)))'));

SELECT * FROM samples;
"""
)

con.sql(
    """
COPY samples TO 'samples.geojson' (FORMAT GDAL, DRIVER 'GeoJSON');
"""
)

con.sql(
    """
WITH a AS (
  SELECT ST_GeomFromText('POLYGON((0 0, 3 0, 3 3, 0 3, 0 0))') AS g
), b AS (
  SELECT ST_GeomFromText('POLYGON((2 -1, 5 -1, 5 2, 2 2, 2 -1))') AS g
)
SELECT ST_AsText(ST_Intersection(a.g, b.g)) AS inter,
       ST_AsText(ST_Difference(a.g, b.g)) AS only_a,
       ST_AsText(ST_Union(a.g, b.g)) AS unioned
FROM a, b;
"""
)
